// // This module generates a single-bit output based on a given 5-bit opcode.
// The output, PCImm, will be LOW (0) when the opcode matches either 5'b00100 or 5'b00110, indicating specific control conditions, and HIGH (1) otherwise.
module top_module(OpCode, PCImm);input [4:0]	OpCode;
output		PCImm;

assign PCImm = ((OpCode == 5'b00100) | (OpCode == 5'b00110)) ? 1'b1 : 1'b0;

endmodule
